#!run
import {createWorker} from "@acepad/worker";
import {sibling} from "@acepad/here";
export async function main(){
  const w=await createWorker(sibling(import.meta.url,"simple-worker.js"));
  w.addEventListener("message",({data})=>{
    if(typeof data!=="number")return;
    this.echo("recv",data);// 42
  });
  this.echo("Worker created. Message will be sent in 1 sec.");
  await this.sleep(1);
  w.postMessage(21);
}
